sql:
SELECT status_name
FROM listing_status
WHERE status_change_date > '2023-04-01';

SELECT report_data
FROM reports
WHERE generated_by = (SELECT user_id FROM users WHERE user_name = 'Admin User');

SELECT agent_id, total_sales
FROM agents
WHERE total_sales > (
  SELECT AVG(total_sales)
  FROM agents
);

external_knowledge:
- 'real estate treasures' metaphorically represents high-priced listings;
- 'valued beyond a million' refers to listings priced over 1,000,000 units;
- 'harbor more than a dozen' means cities have more than 10 such listings.

sql:
SELECT agent_name
FROM agents
WHERE agent_id = 0;

SELECT city_name
FROM cities
WHERE median_income = (SELECT MAX(median_income) FROM cities);

SELECT listing_price
FROM listings
WHERE listing_id > 5;

SELECT listing_price, sq_ft, price_per_sq_ft, bedrooms, bathrooms, year_built, description
FROM listings
WHERE listing_id = 1;
